            journal.id,
            journal.has_liked,
            journal.comment_count?.[0]?.count,
            journal.has_bookmarked,
            journal.like_count?.[0]?.count,
            journal.bookmark_count?.[0]?.count,
            journal.users.badge,
            journal?.post_type,
            journal?.canvas_doc,
            journal?.user_reaction,
            journal?.reaction_count?.[0]?.count || 0
        );
    }

    const handleRemixCanvas = (e, journal) => {
        e.stopPropagation();
        if(!session){
            openAuthModal();
